  @CategoryID_0dfae68d = '0A7E9FD9-45BD-4ECF-ABD2-0EFF73C879E6'
SET
  @Description_0dfae68d = N'Run a Record Process on demand over an optional runtime scope (selected records / view / list / filter), optionally as a dry-run preview that computes the per-record changes without writing. Returns the run summary (status + processed/success/error/skipped counts + the MJ: Process Runs ID). Implemented by RecordProcessRunNowServerOperation in @memberjunction/record-set-processor.'
SET
  @InputTypeName_0dfae68d = N'RecordProcessRunNowInput'
SET
  @InputTypeDefinition_0dfae68d = N'/** Runtime scope override for a Record Process run (instead of the stored Scope). */
export type RecordProcessScopeOverride =
    | { Kind: ''records''; RecordIDs: string[] }
    | { Kind: ''view''; ViewID: string }
    | { Kind: ''list''; ListID: string }
    | { Kind: ''filter''; Filter?: string };

/** Input for `RecordProcess.RunNow`. */
export interface RecordProcessRunNowInput {
    /** The `MJ: Record Processes` definition to run. */
    recordProcessID: string;
    /** When set, processes just this single record instead of the configured scope. */
    singleRecordID?: string;
    /** Compute the per-record changes WITHOUT writing (FieldRules work type) — powers the preview. */
    dryRun?: boolean;
    /** Runtime scope override (selected rows / a view / list / filter), used instead of the stored Scope. */
    scope?: RecordProcessScopeOverride;
}
'
SET
  @InputTypeIsArray_0dfae68d = 0
SET
  @OutputTypeName_0dfae68d = N'RecordProcessRunNowOutput'
SET
  @OutputTypeDefinition_0dfae68d = N'/** Output of `RecordProcess.RunNow` — the run summary. */
export interface RecordProcessRunNowOutput {
    /** ID of the persisted `MJ: Process Runs` row. */
    processRunID?: string;
    /** Run-level status (`Completed` / `Failed` / `Cancelled` / …). */
    status: string;
    /** Records the run touched. */
    processed: number;
    /** Records that succeeded (in dry-run, records with a computed preview). */
    success: number;
    /** Records that errored. */
    error: number;
    /** Records skipped (no rule matched / nothing changed). */
    skipped: number;
    /** Run-level error detail when `status` is not `Completed`. */
    errorMessage?: string;
}
'
